"use strict";const searchBox=document.getElementById("search-input"),postsPageUrl=new URL(`${window.location.protocol}//${window.location.host}/posts/`);searchBox.onkeyup=function(e){if("Enter"==e.key){let windowParams=new URLSearchParams;windowParams.set("tags",searchBox.value),postsPageUrl.search=windowParams.toString(),location.href=postsPageUrl.href}};